    public class StreamBodyController : ControllerBase
    {
        private readonly global::IStreamBodyService iStreamBodyService;
        public StreamBodyController(global::IStreamBodyService iStreamBodyService)
        {
            this.iStreamBodyService = iStreamBodyService;
        }

        [Route("UploadFile")]
        [HttpPost]
        public void UploadFile([FromForm] __UploadFile_FormArg arg)
        {
            using var __sb_file = YS.Knife.StreamBody.FromStream(arg.file.OpenReadStream(), arg.file.ContentType, arg.file.FileName, arg.file.Length);
            this.iStreamBodyService.UploadFile(__sb_file);
        }

        public record __UploadFile_FormArg(global::Microsoft.AspNetCore.Http.IFormFile file);
    }
